 1→import { useEffect } from "react";
 2→import { ensureMeta, ensureJsonLd, ensureLink, removeElementById } from "./seoUtils.js";
 3→import { SITE_URL } from "./seoConfig.js";
 4→
 5→const PROFILE_SEO_IDS = [
 6→  "profile-seo-og-type",
 7→  "profile-seo-og-title",
 8→  "profile-seo-og-description",
 9→  "profile-seo-og-image",
10→  "profile-seo-og-url",
11→  "profile-seo-twitter-title",
12→  "profile-seo-twitter-description",
13→  "profile-seo-twitter-image",
14→  "profile-seo-person-ld",
15→  "profile-seo-canonical",
16→];
