18→const useProfileSeo = (userData, username) => {
19→  useEffect(() => {
20→    if (!userData?.name) return;
21→
22→    const displayName = userData.name;
23→    const title = `${displayName}'s Profile | Iskryb`;
24→    const description = userData.bio || `View ${displayName}'s journals and opinions on Iskryb.`;
25→    const profileUrl = username ? `${SITE_URL}/u/${username}` : "";
26→    const ogImage = userData.image_url || `${SITE_URL}/assets/no-image.png`;
27→
28→    document.title = title;
29→
30→    ensureMeta("seo-description", "name", "description", description);
31→
32→    ensureMeta("profile-seo-og-type", "property", "og:type", "profile");
33→    ensureMeta("profile-seo-og-title", "property", "og:title", title);
34→    ensureMeta("profile-seo-og-description", "property", "og:description", description);
35→    ensureMeta("profile-seo-og-image", "property", "og:image", ogImage);
36→    if (profileUrl) {
37→      ensureMeta("profile-seo-og-url", "property", "og:url", profileUrl);
38→    }
39→
40→    ensureMeta("profile-seo-twitter-title", "name", "twitter:title", title);
41→    ensureMeta("profile-seo-twitter-description", "name", "twitter:description", description);
42→    ensureMeta("profile-seo-twitter-image", "name", "twitter:image", ogImage);
43→
44→    if (profileUrl) {
45→      ensureLink("profile-seo-canonical", "canonical", profileUrl);
46→    }
47→
48→    const personLd = {
49→      "@context": "https://schema.org",
50→      "@type": "Person",
51→      name: displayName,
52→    };
53→    if (profileUrl) personLd.url = profileUrl;
54→    if (userData.image_url) personLd.image = userData.image_url;
55→    if (userData.bio) personLd.description = userData.bio;
56→
57→    ensureJsonLd("profile-seo-person-ld", personLd);
58→
59→    return () => {
60→      document.title = "Iskryb | Social Journaling and Opinions";
61→      PROFILE_SEO_IDS.forEach(removeElementById);
62→    };
63→  }, [userData?.name, userData?.bio, userData?.image_url, username]);
64→};
65→
66→export default useProfileSeo;
