 95→const DYNAMIC_PATTERNS = [
 96→  {
 97→    test: (pathname) => /^\/home\/post\/[^/]+(?:\/[^/]+)?$/.test(pathname),
 98→    seo: (pathname) => {
 99→      const match = pathname.match(/^\/home\/post\/([^/]+)/);
100→      const journalId = match ? match[1] : null;
101→      return {
102→        title: `${SITE_NAME} Post`,
103→        description: "Read community journals and discussions on Iskryb.",
104→        canonicalPath: journalId ? `/home/post/${journalId}` : null,
105→        robots: "index,follow",
106→      };
107→    },
108→  },
109→  {
110→    test: (pathname) => /^\/u\/[^/]+/.test(pathname),
111→    seo: (pathname) => {
112→      const username = pathname.split("/")[2];
113→      return {
114→        title: `${username}'s Profile | ${SITE_NAME}`,
115→        description: `View ${username}'s journals and opinions on Iskryb.`,
116→        canonicalPath: `/u/${username}`,
117→        robots: "index,follow",
