123→export const buildAbsoluteUrl = (pathOrUrl = "/") => {
124→  if (!pathOrUrl) {
125→    return `${SITE_URL}/`;
126→  }
127→
128→  if (/^https?:\/\//i.test(pathOrUrl)) {
129→    return pathOrUrl;
130→  }
131→
132→  return new URL(pathOrUrl, `${SITE_URL}/`).toString();
133→};
134→
135→export const getSeoForPath = (pathname) => {
136→  const normalized = pathname || "/";
137→  const exactMatch = SEO_ROUTES.find((route) => route.path === normalized);
138→  if (exactMatch) {
139→    return { ...DEFAULT_SEO, ...exactMatch };
140→  }
141→
142→  const dynamicMatch = DYNAMIC_PATTERNS.find((entry) => entry.test(normalized));
143→  if (dynamicMatch) {
144→    const seo = typeof dynamicMatch.seo === "function"
145→      ? dynamicMatch.seo(normalized)
146→      : dynamicMatch.seo;
147→    return { ...DEFAULT_SEO, ...seo };
148→  }
149→
150→  return { ...DEFAULT_SEO };
151→};
152→
153→export const getPrerenderRoutes = () =>
154→  SEO_ROUTES.filter((route) => route.prerender).map((route) => route.path);
155→
156→export const getSitemapRoutes = () =>
157→  SEO_ROUTES.filter((route) => route.sitemap).map((route) => ({
158→    path: route.path,
159→    ...route.sitemap,
160→  }));
