 1→import { useEffect } from "react";
 2→import { useLocation } from "react-router-dom";
 3→import {
 4→  DEFAULT_OG_IMAGE,
 5→  DEFAULT_OG_IMAGE_HEIGHT,
 6→  DEFAULT_OG_IMAGE_WIDTH,
 7→  ORGANIZATION_SCHEMA,
 8→  buildAbsoluteUrl,
 9→  buildWebsiteSchema,
10→  getSeoForPath,
11→} from "./seoConfig.js";
12→import { ensureMeta, removeElementById, ensureLink, ensureJsonLd } from "./seoUtils.js";
13→
14→const SeoManager = () => {
15→  const { pathname } = useLocation();
16→
17→  useEffect(() => {
18→    const seo = getSeoForPath(pathname);
19→    const canonicalUrl = buildAbsoluteUrl(seo.canonicalPath || pathname);
20→    const ogTitle = seo.ogTitle || seo.title;
21→    const ogDescription = seo.ogDescription || seo.description;
22→    const ogImage = seo.ogImage || DEFAULT_OG_IMAGE;
23→    const fbAppId = (import.meta.env.VITE_FB_APP_ID || "").trim();
24→
25→    document.title = seo.title;
26→
27→    ensureMeta("seo-description", "name", "description", seo.description);
28→    ensureMeta("seo-robots", "name", "robots", seo.robots || "index,follow");
29→
30→    ensureMeta("seo-og-type", "property", "og:type", "website");
31→    ensureMeta("seo-og-url", "property", "og:url", canonicalUrl);
32→    ensureMeta("seo-og-title", "property", "og:title", ogTitle);
33→    ensureMeta("seo-og-description", "property", "og:description", ogDescription);
34→    ensureMeta("seo-og-image", "property", "og:image", ogImage);
35→    ensureMeta("seo-og-image-width", "property", "og:image:width", String(DEFAULT_OG_IMAGE_WIDTH));
36→    ensureMeta("seo-og-image-height", "property", "og:image:height", String(DEFAULT_OG_IMAGE_HEIGHT));
37→    ensureMeta("seo-og-site-name", "property", "og:site_name", "Iskryb");
38→    if (fbAppId) {
39→      ensureMeta("seo-fb-app-id", "property", "fb:app_id", fbAppId);
40→    } else {
41→      removeElementById("seo-fb-app-id");
42→    }
43→
44→    ensureMeta("seo-twitter-card", "name", "twitter:card", "summary_large_image");
45→    ensureMeta("seo-twitter-title", "name", "twitter:title", ogTitle);
46→    ensureMeta("seo-twitter-description", "name", "twitter:description", ogDescription);
47→    ensureMeta("seo-twitter-image", "name", "twitter:image", ogImage);
48→    ensureMeta("seo-twitter-image-width", "name", "twitter:image:width", String(DEFAULT_OG_IMAGE_WIDTH));
49→    ensureMeta("seo-twitter-image-height", "name", "twitter:image:height", String(DEFAULT_OG_IMAGE_HEIGHT));
50→
51→    ensureLink("seo-canonical", "canonical", canonicalUrl);
52→    ensureLink("seo-hreflang-en", "alternate", canonicalUrl, { hreflang: "en-US" });
53→    ensureLink("seo-hreflang-default", "alternate", canonicalUrl, {
54→      hreflang: "x-default",
55→    });
56→
57→    ensureJsonLd("seo-ld-website", buildWebsiteSchema(canonicalUrl));
58→    ensureJsonLd("seo-ld-organization", ORGANIZATION_SCHEMA);
59→  }, [pathname]);
60→
61→  return null;
62→};
63→
64→export default SeoManager;
