 15→const DEFAULT_OG_IMAGE_URL = `${SITE_URL}/assets/no-image.png`;
 16→const DEFAULT_OG_IMAGE_WIDTH = 1200;
 17→const DEFAULT_OG_IMAGE_HEIGHT = 630;
 18→const SOCIAL_PREVIEW_MAX_CHARS = 160;
