 26→const normalizeWhitespace = (value) => String(value ?? '')
 27→    .replace(/\s+/g, ' ')
 28→    .trim();
 29→
 30→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 31→    const normalized = normalizeWhitespace(value);
 32→    if (!normalized) return '';
 33→    if (normalized.length <= maxLength) return normalized;
 34→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 35→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 36→};
