 46→const getRequestOrigin = (req) => {
 47→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 48→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 49→    const host = forwardedHost || req.get('host') || '';
 50→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 51→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 52→        ? forwardedProto
 53→        : requestProtocol === 'http' || requestProtocol === 'https'
 54→            ? requestProtocol
 55→            : 'https';
 56→
 57→    if (!host) {
 58→        return SITE_URL;
 59→    }
 60→
 61→    return `${protocol}://${host}`;
 62→};
 63→
 64→const pickFirstNonEmptyString = (...values) => {
 65→    for (const value of values) {
 66→        if (typeof value === 'string') {
 67→            const trimmed = value.trim();
 68→            if (trimmed) return trimmed;
 69→        }
 70→    }
 71→    return '';
 72→};
 73→
 74→const parseImageDimension = (value) => {
 75→    const parsed = Number(value);
 76→    if (!Number.isFinite(parsed)) return undefined;
 77→    return parsed;
 78→};
 79→
 80→const imageFromNodeLike = (nodeLike) => {
 81→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 82→
 83→    const src = pickFirstNonEmptyString(
 84→        nodeLike.src,
 85→        nodeLike.url,
 86→        nodeLike.image_url,
 87→        nodeLike.imageUrl,
 88→        nodeLike?.payload?.src,
 89→        nodeLike?.data?.src
 90→    );
 91→    if (!src) return null;
 92→
 93→    return {
 94→        src,
 95→        width: parseImageDimension(nodeLike.width),
 96→        height: parseImageDimension(nodeLike.height),
 97→    };
 98→};
