163→const buildShareMetaFromJournal = (journal) => {
164→    const lexicalData = extractFromLexical(journal?.content);
165→    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
166→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
167→    const title = normalizedTitle || 'Untitled Post';
168→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
169→
170→    let description = lexicalData.text || '';
171→    if (!description && canvasData.text) {
172→        description = canvasData.text;
173→    }
174→    if (!description) {
175→        description = `Read "${title}" by ${authorName} on Iskryb`;
176→    }
177→
178→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
179→    let imageCandidateSource = 'fallback';
180→    if (lexicalData.image?.src) {
181→        imageCandidate = lexicalData.image.src;
182→        imageCandidateSource = 'lexical';
183→    } else if (canvasData.image?.src) {
184→        imageCandidate = canvasData.image.src;
185→        imageCandidateSource = 'canvas';
186→    } else if (journal?.users?.image_url) {
187→        imageCandidate = journal.users.image_url;
188→        imageCandidateSource = 'author_avatar';
189→    }
190→
191→    return {
192→        title,
193→        normalizedTitle,
194→        description: toPreviewText(description),
195→        imageCandidate,
196→        imageCandidateSource
197→    };
198→};
