447→app.get('/share/post/:journalId/image', async (req, res) => {
448→    const { journalId } = req.params;
449→    const debugMode = isShareImageDebugRequest(req);
450→    const debugPayload = {
451→        ok: false,
452→        fallback: false,
453→        journalId,
454→        stage: 'start',
455→        reason: '',
456→        meta: {
457→            imageCandidateSource: null,
458→            imageCandidateRaw: null,
459→            imageCandidateResolved: null,
460→            upstreamFinalUrl: null,
461→            upstreamContentType: null,
462→            upstreamBytes: null,
463→            outputBytes: null,
464→        },
465→    };
466→
467→    const fallbackWithReason = (reason) => {
468→        debugPayload.ok = false;
469→        debugPayload.fallback = true;
470→        debugPayload.stage = 'fallback';
471→        debugPayload.reason = reason;
472→        if (debugMode) {
473→            return sendShareImageDebug(res, debugPayload);
474→        }
475→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
476→    };
477→
478→    try {
479→        const journal = await getShareJournal(journalId);
480→        debugPayload.stage = 'journal_loaded';
481→        if (!journal) {
482→            return fallbackWithReason('journal_not_found');
483→        }
484→
485→        const shareMeta = buildShareMetaFromJournal(journal);
486→        debugPayload.stage = 'candidate_extracted';
487→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
488→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
489→
490→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
491→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
492→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
493→            return fallbackWithReason(candidateEvaluation.reason);
494→        }
495→
496→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
497→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
498→            return fallbackWithReason('candidate_is_default_fallback');
499→        }
500→
501→        debugPayload.stage = 'fetching_upstream';
502→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
503→        debugPayload.stage = 'upstream_loaded';
504→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
505→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
506→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
507→
508→        debugPayload.stage = 'converting_image';
509→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
510→        debugPayload.stage = 'converted_image';
511→        debugPayload.ok = true;
512→        debugPayload.reason = 'ok';
513→        debugPayload.meta.outputBytes = ogImageBuffer.length;
514→
515→        if (debugMode) {
516→            return sendShareImageDebug(res, debugPayload);
517→        }
518→
519→        res.set('Content-Type', 'image/jpeg');
520→        res.set('Cache-Control', 'public, max-age=3600');
521→        return res.send(ogImageBuffer);
522→    } catch (err) {
523→        debugPayload.stage = 'error';
524→        debugPayload.reason = err?.message || 'unknown_error';
525→        console.error('share image route error:', err?.message || err);
526→        return fallbackWithReason(debugPayload.reason);
527→    }
528→});
