  25→const extractBearerToken = (authHeader = "") => {
  26→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
  27→    if (!trimmed) return "";
  28→
  29→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
  30→    if (bearerMatch?.[1]) {
  31→        return bearerMatch[1].trim();
  32→    }
  33→
  34→    return trimmed;
  35→};
  36→
  37→const resolveAuthUser = async (token) => {
  38→    if (!token) {
  39→        return { user: null, error: null };
  40→    }
  41→
  42→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
  43→    if (authError || !authData?.user?.id) {
  44→        return { user: null, error: authError || new Error("missing user id") };
  45→    }
  46→
  47→    return { user: authData.user, error: null };
  48→};
  49→
  50→const requireAuth = async (req, res, next) => {
  51→    const token = extractBearerToken(req.headers?.authorization);
  52→    if (!token) {
  53→        return res.status(401).json({ error: 'not authorized' });
  54→    }
  55→
  56→    const { user, error } = await resolveAuthUser(token);
  57→    if (error || !user?.id) {
  58→        console.error('auth middleware error:', error?.message || 'missing user id');
  59→        return res.status(401).json({ error: 'not authorized' });
  60→    }
  61→
  62→    req.userId = user.id;
  63→    req.authUser = user;
  64→    return next();
  65→};
  66→
  67→const optionalAuth = async (req, _res, next) => {
  68→    const token = extractBearerToken(req.headers?.authorization);
  69→    if (!token) {
  70→        return next();
  71→    }
  72→
  73→    const { user } = await resolveAuthUser(token);
  74→    if (user?.id) {
  75→        req.userId = user.id;
  76→        req.authUser = user;
  77→    }
  78→
  79→    return next();
  80→};
